------------------------------------------------------------------
---战斗频繁使用的一些对象、资源缓存
------------------------------------------------------------------
---@class LFightCache
local LFightCache = LxClass("LFightCache", nil)
------------------------------------------------------------------

local CS = CS
local LFightHudItem = LxRequire("LApp.gameplay.fight.View.LFightHudItem")

------------------------------------------------------------------
function LFightCache:LFightCache()
	---战斗飘字缓存
	---@type LCacheMgr
	self._hudObjCacheMgr = nil

	---血条缓存
	---@type LCacheMgr
	self._bloodObjCacheMgr = nil
end

-------------------------------------------------------------------
function LFightCache:Create()
	self:InitHudCache()
	self:InitBloodCache()
end

function LFightCache:Destroy()
	if self._isDestroy then return end
	if self._hudObjCacheMgr ~= nil then
		self._hudObjCacheMgr:Destroy()
	end

	if self._bloodObjCacheMgr ~= nil then
		self._bloodObjCacheMgr:Destroy()
	end

	LxResUtil.DestroyObject(self._btHudTemplateTrans.gameObject, self._hudBundleName)
	LxResUtil.DestroyObject(self._btHudNodeTemplateGo.gameObject, self._hudNodeBundleName)

	table.removeall(self)
	self._isDestroy = true
end
------------------------------------------------------------------
---战斗飘字初始化
function LFightCache:InitHudCache()
	if self._bInitHudCache then
		return
	end
	self._bInitHudCache = true

	self._hudObjCacheMgr = LCacheMgr:New()

	local uiFightRoot = LGameUI.GetUIFight()
	local hudRootTrans = CS.FindTrans(uiFightRoot,"UIHud")
	self._hudRootTrans = hudRootTrans

	self._wordRootTrans = CS.FindTrans(hudRootTrans,"WordRoot")

	local hudTemplateRoot = CS.FindTrans(hudRootTrans,"Template")
	self._hudTemplateRoot = hudTemplateRoot
	CS.ShowObject(hudTemplateRoot,false)

	local colTransList = {}
	self._hudColTransList = colTransList
	for k=1, 3 do
		colTransList[k] = CS.FindTrans(hudRootTrans, "Col"..k)
	end
	
	local resPath = CS.ResPath(CS.RES_UI_COMMON, "HUD")
	local bundleName = CS.FormatBundleNameByPath(resPath)
	self._hudBundleName = bundleName
	local mainScene = GF.GetMainScene()
	local btHudTemplate = LxResUtil.NewObject(mainScene:GetHudAssetObject("HUD"))
	local btHudTemplateTrans = btHudTemplate.transform
	CS.SetParentTrans(btHudTemplateTrans,hudTemplateRoot)
	self._btHudTemplateTrans = btHudTemplateTrans
	
	resPath = CS.ResPath(CS.RES_UI_COMMON, "BtHudNode")
	bundleName = CS.FormatBundleNameByPath(resPath)
	self._hudNodeBundleName = bundleName
	local btHudNodeTemplate = LxResUtil.NewObject(mainScene:GetHudAssetObject("BtHudNode"))
	local btHudNodeTemplateTrans = btHudNodeTemplate.transform
	CS.SetParentTrans(btHudNodeTemplateTrans,hudTemplateRoot)
	self._btHudNodeTemplateGo = btHudNodeTemplateTrans.gameObject

	local btHurt = CS.FindTrans(btHudTemplateTrans,"Hurt").gameObject
	local btCrit = CS.FindTrans(btHudTemplateTrans,"Crit").gameObject
	local btWorld = CS.FindTrans(btHudTemplateTrans,"World").gameObject
	local btHeal = CS.FindTrans(btHudTemplateTrans,"Heal").gameObject
	local btCommon = CS.FindTrans(btHudTemplateTrans,"Common").gameObject
	local buffText = CS.FindTrans(btHudTemplateTrans,"BuffText").gameObject
	local skillText = CS.FindTrans(btHudTemplateTrans,"SkillText").gameObject
	local treaSkill = CS.FindTrans(btHudTemplateTrans,"TreaSkill").gameObject
	local btStrike = CS.FindTrans(btHudTemplateTrans,"Strike").gameObject

	self._dicTemplateMap = {
		[LFightConst.HUD_HURT] = btHurt,
		[LFightConst.HUD_CRIT] = btCrit,
		[LFightConst.HUD_WORLD] = btWorld,
		[LFightConst.HUD_HEAL] = btHeal,
		[LFightConst.HUD_COMMON] = btCommon,
		[LFightConst.HUD_TIP] = btCommon,
		[LFightConst.HUD_BUFF] = buffText,
		[LFightConst.HUD_SKILL] = skillText,
		[LFightConst.HUD_BTNODE] = self._btHudNodeTemplateGo,
		[LFightConst.HUD_TREA] = treaSkill,
		[LFightConst.HUD_STRIKE] = btStrike,

	}
end

function LFightCache:InnerGenerateHudItem(hudType)
	local goTemplate = self._dicTemplateMap[hudType]
	if not goTemplate then
		return nil
	end
	local cloneGo = LxResUtil.NewObject(goTemplate)
	local hudItem = LFightHudItem:New(hudType)
	hudItem:SetHudGameObj(cloneGo)
	CS.SetParentTrans(hudItem:GetHudTrans(), self._hudTemplateRoot)
	return hudItem
end

---获取缓存的hudItem类实例
---@param hudType number @recomand hud类型
---@return LFightHudItem
function LFightCache:GetHudItemFromCache(hudType)
	local hudItem = self._hudObjCacheMgr:GetCache(hudType, LFightCache.InnerGenerateHudItem, self, hudType)
	return hudItem
end

function LFightCache:ReturnHudItemToCache(hudType,hudItem)
	self._hudObjCacheMgr:ReleaseCache(hudType, hudItem)
	CS.SetParentTrans(hudItem:GetHudTrans(),self._hudTemplateRoot)
	return true
end

-----------------------------------------------------------------
function LFightCache:GetHudRootTrans()
	return self._hudRootTrans
end

function LFightCache:GetWordRootTrans()
	return self._wordRootTrans
end

function LFightCache:GetHudRootTransByColIndex(colIdx)
	local rootTrans = self._hudColTransList[colIdx]
	if not rootTrans then
		return self:GetHudRootTrans()
	end
	return rootTrans
end



------------------------------------------------------------------
---血条初始化
function LFightCache:InitBloodCache()

end

-------------------------------------------------------------------
return LFightCache
